import{_ as a,o as i,c as s,ag as t}from"./chunks/framework.BDReElpY.js";const u=JSON.parse('{"title":"SIR Optimization Pipeline","description":"","frontmatter":{},"headers":[],"relativePath":"guide/simd/sir-pipeline.md","filePath":"guide/simd/sir-pipeline.md"}'),n={name:"guide/simd/sir-pipeline.md"};function l(r,e,o,d,c,p){return i(),s("div",null,[...e[0]||(e[0]=[t(`<h1 id="sir-optimization-pipeline" tabindex="-1">SIR Optimization Pipeline <a class="header-anchor" href="#sir-optimization-pipeline" aria-label="Permalink to &quot;SIR Optimization Pipeline&quot;">​</a></h1><p>This page describes the current pipeline conservatively: what is clearly implemented, what route a workload tends to take, and where the sharp edges still are.</p><h2 id="high-level-picture" tabindex="-1">High-level picture <a class="header-anchor" href="#high-level-picture" aria-label="Permalink to &quot;High-level picture&quot;">​</a></h2><p>There are two different optimization routes that often get conflated:</p><ul><li>compiler-side inline SIMD for qualifying small static arrays</li><li>SIR lowering and backend dispatch for tensor or graph workloads</li></ul><p>Conceptually:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>source code</span></span>
<span class="line"><span>  -&gt; HIR</span></span>
<span class="line"><span>  -&gt; either small-array inline SIMD</span></span>
<span class="line"><span>  -&gt; or SIR graph lowering</span></span>
<span class="line"><span>  -&gt; backend selection</span></span>
<span class="line"><span>  -&gt; LLVM IR / target code</span></span></code></pre></div><h2 id="route-1-inline-simd-for-small-arrays" tabindex="-1">Route 1: inline SIMD for small arrays <a class="header-anchor" href="#route-1-inline-simd-for-small-arrays" aria-label="Permalink to &quot;Route 1: inline SIMD for small arrays&quot;">​</a></h2><p>The compiler has a dedicated <code>simd_small</code> path for qualifying fixed-size arrays.</p><p>The current backend threshold is explicit:</p><ul><li>maximum 64 bytes total</li><li>maximum 64 elements</li><li>element count must be a power of two</li></ul><p>That threshold is implemented in <code>crates/vex-sir/src/codegen/backends/simd/inline.rs</code> and mirrored by the small-array codegen helpers in <code>crates/vex-compiler/src/codegen_hir/expr/simd_small</code>.</p><p>Typical examples on this path are:</p><ul><li>element-wise arithmetic on <code>[T; N]</code></li><li>vector comparisons on <code>[T; N]</code></li><li>reductions such as <code>\\+</code> and <code>\\&gt;</code> on small arrays</li></ul><p>Example:</p><div class="language-vex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">fn</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> sum8</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(x</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">:</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> [</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">i32</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">; </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">8</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">])</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">:</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> i32</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> {</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">    return</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> \\</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">+</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> x</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p>On this path, the likely evidence in emitted LLVM is:</p><ul><li><code>&lt;N x T&gt;</code> vector values</li><li><code>insertelement</code> chains for tiny literals</li><li><code>llvm.vector.reduce.*</code> intrinsics for reductions</li></ul><h2 id="route-2-sir-for-tensor-and-graph-code" tabindex="-1">Route 2: SIR for tensor and graph code <a class="header-anchor" href="#route-2-sir-for-tensor-and-graph-code" aria-label="Permalink to &quot;Route 2: SIR for tensor and graph code&quot;">​</a></h2><p>When code is written around <code>graph fn</code>, <code>Tensor&lt;T&gt;</code>, or other graph-shaped tensor operations, the compiler lowers into SIR first and then chooses a backend based on shapes and supported node families.</p><p>This route is the right mental model for:</p><ul><li>dynamic tensors</li><li>graph compute</li><li>gather and scatter families</li><li>backend dispatch between CPU SIMD and GPU-style paths</li></ul><h2 id="static-and-dynamic-shape-routing" tabindex="-1">Static and dynamic shape routing <a class="header-anchor" href="#static-and-dynamic-shape-routing" aria-label="Permalink to &quot;Static and dynamic shape routing&quot;">​</a></h2><p>The internal contract distinguishes between static and dynamic shapes:</p><ul><li>static tensors like <code>Tensor&lt;f32, 4&gt;</code> carry fixed shape information</li><li>dynamic tensors like <code>Tensor&lt;f32&gt;</code> lower to <code>%VexDynTensor { ptr, i64 }</code></li><li><code>Span&lt;T&gt;</code> lowers as a non-owning <code>%VexSlice { ptr, i64 }</code></li></ul><p>That distinction is not cosmetic. A dynamic tensor owns storage and participates in drop behavior, while a span is a borrowed view.</p><h2 id="important-coercion-boundary" tabindex="-1">Important coercion boundary <a class="header-anchor" href="#important-coercion-boundary" aria-label="Permalink to &quot;Important coercion boundary&quot;">​</a></h2><p>One of the easy mistakes is assuming every tensor-like value is interchangeable because the layouts look similar.</p><p>They are not.</p><p>The compiler has an explicit safety guard to avoid silently fabricating an owning dynamic tensor from a stack-aliased vector value. Conversions into <code>Tensor&lt;T&gt;</code> must go through the proper owned path.</p><p>In practical terms:</p><ul><li><code>Span&lt;T&gt; -&gt; Tensor&lt;T&gt;</code> should be treated as an owned conversion</li><li><code>Tensor&lt;T&gt;</code> and <code>Span&lt;T&gt;</code> are not just two names for the same thing</li><li>bugs at generic call boundaries have historically shown up exactly here</li></ul><h2 id="backend-capability-in-plain-language" tabindex="-1">Backend capability, in plain language <a class="header-anchor" href="#backend-capability-in-plain-language" aria-label="Permalink to &quot;Backend capability, in plain language&quot;">​</a></h2><p>Current backend support is uneven by operation family.</p><p>The strongest, most stable parts are:</p><ul><li>element-wise tensor math</li><li>reductions</li><li>inline SIMD for small arrays</li><li>mask operations</li></ul><p>More conditional areas include:</p><ul><li>dynamic indexed gather and scatter</li><li>specialized scatter combine variants</li><li>generic tensor arithmetic across arbitrary <code>T</code></li><li>assuming a single fused kernel for every graph-shaped expression</li></ul><p>The current type-shape contract documents one especially important special case: dynamic SIMD indexed routing is intentionally narrow and only kicks in for certain single-node gather and scatter forms.</p><h2 id="what-to-verify-when-performance-matters" tabindex="-1">What to verify when performance matters <a class="header-anchor" href="#what-to-verify-when-performance-matters" aria-label="Permalink to &quot;What to verify when performance matters&quot;">​</a></h2><p>For small arrays:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">vex</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> compile</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --emit-llvm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> file.vx</span></span></code></pre></div><p>Look for:</p><ul><li><code>&lt;N x T&gt;</code> vector operations</li><li><code>llvm.vector.reduce.*</code></li><li>fewer temporary allocas on the hot path</li></ul><p>For tensor and graph workloads, emitted LLVM alone is not the whole story. The more relevant question is whether the workload lowered into the intended SIR route and backend family.</p><h2 id="current-documentation-stance" tabindex="-1">Current documentation stance <a class="header-anchor" href="#current-documentation-stance" aria-label="Permalink to &quot;Current documentation stance&quot;">​</a></h2><p>Treat these as accurate today:</p><ul><li>there is a real inline SIMD threshold at 64 bytes</li><li>small-array reductions use LLVM vector reduction intrinsics</li><li>dynamic tensors are owning <code>{ ptr, i64 }</code> values with drop semantics</li><li>masks and dynamic indexed operations have dedicated backend codepaths</li></ul><p>Do not assume from this page that:</p><ul><li>every qualifying source expression will always fuse the way you expect</li><li>all tensor math is equally mature across all dtypes and backends</li><li>generic <code>Tensor&lt;T&gt;</code> arithmetic is a stable public contract yet</li></ul><h2 id="see-also" tabindex="-1">See also <a class="header-anchor" href="#see-also" aria-label="Permalink to &quot;See also&quot;">​</a></h2><ul><li><a href="./index">SIMD and Auto-Vectorization</a></li><li><a href="./tensor-mask">Tensor and Mask Types</a></li><li><a href="/docs/guide/gpu">GPU Programming</a></li></ul>`,52)])])}const m=a(n,[["render",l]]);export{u as __pageData,m as default};
